from dataclasses import dataclass
from enum import IntEnum
from typing import Optional

class DataTier(IntEnum):
    PUBLIC = 1
    INTERNAL = 2
    CONFIDENTIAL = 3
    RESTRICTED = 4

@dataclass
class ClassifiedArtifact:
    content: str
    tier: DataTier
    source_id: str

    @property
    def permits_external_model(self) -> bool:
        return self.tier <= DataTier.INTERNAL

    @property
    def permits_content_logging(self) -> bool:
        return self.tier <= DataTier.INTERNAL

    @property
    def requires_human_review(self) -> bool:
        return self.tier == DataTier.RESTRICTED

    @property
    def prompt_safe_value(self) -> str:
        """Return value safe to include in prompt per tier rules."""
        if self.tier == DataTier.RESTRICTED:
            # Mask the actual value; return a reference only
            return f"[RESTRICTED:{self.source_id}]"
        return self.content

class ContextAdmissionPolicy:
    """Enforces per-tier handling rules before admitting artifacts to context."""

    def __init__(self, use_private_model_fn, log_fn):
        self._use_private = use_private_model_fn
        self._log = log_fn
        self._context: list[ClassifiedArtifact] = []

    def admit(self, artifact: ClassifiedArtifact) -> str:
        """Admit artifact to context and return prompt-safe value."""
        max_tier = max(
            (a.tier for a in self._context), default=DataTier.PUBLIC
        )
        if artifact.tier > max_tier:
            # Tier escalation: enforce higher-tier model routing
            if artifact.tier >= DataTier.CONFIDENTIAL:
                self._use_private()

        self._context.append(artifact)

        # Audit log — never log Confidential/Restricted content
        if artifact.permits_content_logging:
            self._log(f"ADMIT source={artifact.source_id} tier={artifact.tier.name}")
        else:
            self._log(f"ADMIT source={artifact.source_id} tier={artifact.tier.name} content=REDACTED")

        return artifact.prompt_safe_value

    def current_max_tier(self) -> DataTier:
        if not self._context:
            return DataTier.PUBLIC
        return max(a.tier for a in self._context)

    def purge_restricted(self) -> None:
        """Remove Restricted artifacts from in-memory context after use."""
        self._context = [a for a in self._context if a.tier < DataTier.RESTRICTED]

# Example usage
import logging
logging.basicConfig(level=logging.INFO)

policy = ContextAdmissionPolicy(
    use_private_model_fn=lambda: logging.info("Switching to private model"),
    log_fn=lambda msg: logging.info(msg),
)

doc = ClassifiedArtifact("Patient has diabetes", DataTier.RESTRICTED, "emr-123")
ref = ClassifiedArtifact("Diabetes treatment guidelines", DataTier.PUBLIC, "pub-456")

prompt_val = policy.admit(doc)
pub_val = policy.admit(ref)
print(f"Prompt value for restricted doc: {prompt_val}")
print(f"Requires human review: {doc.requires_human_review}")
policy.purge_restricted()
